// Map a service name to its review category key
export function getCategoryForService(service: string): ReviewCategory {
  const cat = reviewCategories.find(c => c.services.includes(service));
  return cat ?? reviewCategories.find(c => c.key === 'generic')!;
}

// Get reviews for a service (service-specific first, then generic fallback)
export function getReviewsForService(service: string): Review[] {
  const cat = getCategoryForService(service);
  if (cat.key === 'generic') return cat.reviews;
  return [...cat.reviews, ...reviewCategories.find(c => c.key === 'generic')!.reviews];
}
